/**
 * ForgotPasswordForm Component
 *
 * パスワードリセットリクエストフォームコンポーネント。
 * メールアドレスを入力してパスワードリセットリンクを送信します。
 *
 * 使用例:
 * ```tsx
 * <ForgotPasswordForm onSuccess={() => setShowSuccessMessage(true)} />
 * ```
 */

import React, { useState } from 'react';
import InputField from './InputField';
import Button from './Button';
import ErrorMessage from './ErrorMessage';
import { validateForgotPasswordForm } from '../utils/validation';
import { handleNetworkError } from '../utils/errors';
import { usePasswordReset } from '../hooks/usePasswordReset';
import type { ForgotPasswordFormData } from '../types';

export interface ForgotPasswordFormProps {
  /** 送信成功時のコールバック */
  onSuccess?: (email: string) => void;
  /** 送信失敗時のコールバック */
  onError?: (error: string) => void;
}

/**
 * ForgotPasswordFormコンポーネント
 * パスワードリセットリクエストフォームを提供します
 */
const ForgotPasswordForm: React.FC<ForgotPasswordFormProps> = ({ onSuccess, onError }) => {
  const { forgotPassword } = usePasswordReset();
  const [formData, setFormData] = useState<ForgotPasswordFormData>({
    email: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  /**
   * 入力値変更ハンドラー
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
    // エラーをクリア
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }));
    }
    setSubmitError(null);
    setSuccessMessage(null);
  };

  /**
   * フォーム送信ハンドラー
   */
  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitError(null);
    setSuccessMessage(null);

    // バリデーション
    const validationErrors = validateForgotPasswordForm(formData);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    setIsSubmitting(true);

    try {
      // パスワードリセットAPI呼び出し
      const response = await forgotPassword(formData.email);

      // 成功メッセージ表示
      setSuccessMessage(
        response.message ||
          'If an account exists with this email, you will receive password reset instructions.'
      );

      // フォームをクリア
      setFormData({ email: '' });

      // 成功時のコールバック
      if (onSuccess) {
        onSuccess(formData.email);
      }
    } catch (error) {
      // エラーメッセージを取得
      const errorMessage = handleNetworkError(error);
      setSubmitError(errorMessage);

      // エラーコールバック
      if (onError) {
        onError(errorMessage);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4" noValidate>
      {/* Success Message */}
      {successMessage && (
        <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg">
          <p className="text-sm">{successMessage}</p>
        </div>
      )}

      {/* Submit Error Message */}
      {submitError && <ErrorMessage message={submitError} variant="error" />}

      {/* Information Message */}
      {!successMessage && (
        <div className="bg-blue-50 border border-blue-200 text-blue-700 px-4 py-3 rounded-lg">
          <p className="text-sm">
            Enter your email address and we&apos;ll send you instructions to reset your password.
          </p>
        </div>
      )}

      {/* Email Field */}
      <InputField
        type="email"
        name="email"
        label="Email Address"
        value={formData.email}
        onChange={handleChange}
        error={errors.email}
        placeholder="you@example.com"
        required
        autoComplete="email"
        disabled={isSubmitting}
      />

      {/* Submit Button */}
      <Button
        type="submit"
        variant="primary"
        fullWidth
        loading={isSubmitting}
        disabled={isSubmitting}
      >
        {isSubmitting ? 'Sending...' : 'Send Reset Instructions'}
      </Button>

      {/* Back to Login Link */}
      <div className="text-center">
        <a href="/login" className="text-sm text-primary-600 hover:text-primary-700 underline">
          Back to Login
        </a>
      </div>
    </form>
  );
};

export default ForgotPasswordForm;
